// Extract the original user question and pass it directly to DeepQuery
const chatInput = $('When chat message received').first().json.chatInput;

// Remove trigger keywords to get the clean question
const question = chatInput.replace(/deep report[:\s]*/gi, '').trim();

return [{ json: { question } }];

const cleanAnswer = $json.answer
  .replace(/\\n/g, '\n')
  .replace(/^ {4,}/gm, '')  
  .trim();

return { output: '# Deep Query Analysis Report\n\n' + cleanAnswer };
